  1	import * as React from 'react';
  2	import * as _ from 'lodash-es';
  3	import {
  4	  Chart,
  5	  ChartAxis,
  6	  ChartGroup,
  7	  ChartLine,
  8	  ChartVoronoiContainer,
  9	} from '@patternfly/react-charts';
 10	import { Title } from '@patternfly/react-core';
 11	import { HumanizeResult } from '../../types';
 12	import { useCustomTranslation } from '../../useCustomTranslationHook';
 13	import './line-graph.scss';
 14	
 15	type LineDataType = {
 16	  y: HumanizeResult;
 17	  timestamp: Date;
 18	};
 19	
 20	export type LineGraphProps = {
 21	  data: LineDataType[];
 22	  loading?: boolean;
 23	  error?: string;
 24	  // width of the parent div container (of the Chart component) is fluctuating with the graph/chart (even if viewport remains same),
 25	  // causing multiple re-renders if we use useRefWidth on it. So, using useRefWidth on the Card component,
 26	  // as its width will not change unless we change the viewport dimensions.
 27	  width?: number;
 28	  divideBy?: number;
 29	};
 30	
 31	const LineGraph: React.FC<LineGraphProps> = React.memo(
 32	  ({ data, width, divideBy }) => {
 33	    const { t } = useCustomTranslation();
 34	    const lineData = data.map((datum, i) => ({
 35	      x: String(i + 1),
 36	      ...datum,
 37	    }));
 38	    const mappedLineData = lineData.map((datum) => ({
 39	      ...datum,
 40	      y: datum.y.value,
 41	      yString: datum.y.string,
 42	    }));
 43	
 44	    const dataUnavailable = _.isEmpty(data);
 45	
 46	    const unit = !dataUnavailable ? lineData[0].y.unit : '';
 47	    const latestValue = !dataUnavailable
 48	      ? lineData[lineData.length - 1].y.string
 49	      : '';
 50	    return !dataUnavailable ? (
 51	      <div className="odf-lineGraph">
 52	        <div className="pf-v6-u-display-none-on-md pf-v6-u-display-inline-block-on-lg pf-v5-u-w-95-lg">
 53	          <Chart
 54	            containerComponent={
 55	              <ChartVoronoiContainer
 56	                labels={({ datum }) =>
 57	                  `${datum.yString} at ${datum.timestamp.toLocaleTimeString()}`
 58	                }
 59	                constrainToVisibleArea
 60	              />
 61	            }
 62	            height={150}
 63	            padding={{
 64	              bottom: 20,
 65	              left: 95,
 66	              right: 15, // Adjusted to accommodate legend
 67	              top: 20,
 68	            }}
 69	            width={width / divideBy || width}
 70	          >
 71	            <ChartAxis
 72	              dependentAxis
 73	              showGrid
 74	              tickCount={2}
 75	              tickFormat={(tick, _index, _ticks) => {
 76	                return `${tick} ${unit}`;
 77	              }}
 78	              tickValues={
 79	                mappedLineData.length === 1 ? [mappedLineData[0].y] : undefined
 80	              }
 81	            />
 82	            <ChartGroup>
 83	              <ChartLine data={mappedLineData} />
 84	            </ChartGroup>
 85	          </Chart>
 86	        </div>
 87	        <div className="pf-v5-u-w-5-lg pf-v6-u-w-100-md odf-valueBox">
 88	          <div>
 89	            <Title headingLevel="h5" size="md">
 90	              {latestValue}
 91	            </Title>
 92	          </div>
 93	          <div>{t('Current')}</div>
 94	        </div>
 95	      </div>
 96	    ) : (
 97	      <>-</>
 98	    );
 99	  }
100	);
101	
102	export default LineGraph;

